  ('medical-tech-moex-20038', 'medical-tech', 'medical-tech-moex-094-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '下列何種狀況不會干擾第八凝血因子活性檢驗？ 輸注冷凍沈澱品（Cryoprecipitate）  肝素（Heparin）治療 紅斑性狼瘡抗凝血因子（Lupus anticoagulant）  口服抗凝固劑', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:14+00:00", "source_pdf_sha1": "96d440809c0b", "answer_pdf_sha1": "bc22c58d926f", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "105", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 47, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20039', 'medical-tech', 'medical-tech-moex-094-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '下列何者是Prothrombin time（PT）實驗結果最常見的表示法？ 秒數   百分比   INR   凝固因子含量', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:14+00:00", "source_pdf_sha1": "96d440809c0b", "answer_pdf_sha1": "bc22c58d926f", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "105", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 48, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
