  ('medical-tech-moex-20047', 'medical-tech', 'medical-tech-moex-094-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '有關A 型血友病之臨床症狀，下列何者正確？ 重度（severe type）病人其血漿中第八因子含量低於5％ 輕度（mild type）病人常會有自然出血現象 血小板功能正常 von Willebrand因子缺乏是造成輕度血友病的原因', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:14+00:00", "source_pdf_sha1": "96d440809c0b", "answer_pdf_sha1": "bc22c58d926f", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "105", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 56, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL)
